/* ==========================================================================
   ToggleButton — hover/pressed via direct background-color + color-mix().
   Elevation controls the chrome level:
     elevated — bg-primary + shadow  (default)
     flat     — border only
     none     — ghost (transparent, no border, no shadow)
     floating — bg-primary + FAB-strength shadow
   ========================================================================== */

.toggle-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  border-radius: var(--dimension-radius-050);
  cursor: pointer;
  position: relative;
  transition: transform var(--effect-motion-short-2);
  height: var(--dimension-size-400);
  font-family: inherit;
  background: transparent;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;

  /* Interaction — ghost defaults */
  --_hover-bg: var(--color-interaction-hover);
  --_pressed-bg: var(--color-interaction-pressed);
  --_border: var(--color-border-tertiary);
}

.toggle-btn:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

.toggle-btn:hover:not(.inactive) {
  background-color: var(--_hover-bg);
}

.toggle-btn:active:not(.inactive) {
  background-color: var(--_pressed-bg);
  transform: scale(var(--dimension-scale-subtle));
}

/* ==========================================================================
   Background context — parent surface awareness
   ========================================================================== */

.onMedium {
  --_hover-bg: var(--color-interaction-on-medium-background-hover);
  --_pressed-bg: var(--color-interaction-on-medium-background-pressed);
  --_border: var(--color-border-on-medium-background-tertiary);
}

.onBold {
  --_hover-bg: var(--color-interaction-on-bold-background-hover);
  --_pressed-bg: var(--color-interaction-on-bold-background-pressed);
  --_border: var(--color-border-on-bold-background-tertiary);
}

.onStrong {
  --_hover-bg: var(--color-interaction-on-strong-background-hover);
  --_pressed-bg: var(--color-interaction-on-strong-background-pressed);
  --_border: var(--color-border-on-strong-background-tertiary);
}

.onAlwaysDark {
  --_hover-bg: var(--color-always-dark-interaction-hover);
  --_pressed-bg: var(--color-always-dark-interaction-pressed);
  --_border: var(--color-always-dark-border-tertiary);
}

/* ==========================================================================
   Elevation levels
   ========================================================================== */

/* ── Elevated (default): bg-primary + shadow ───────────────────────────── */

.elevationElevated {
  background-color: var(--color-background-primary);
  box-shadow: var(--effect-elevation-elevated-sm);
  color: var(--color-foreground-secondary);
  --_hover-bg: color-mix(in oklch, var(--color-background-primary) 90%, var(--color-foreground-primary));
  --_pressed-bg: color-mix(in oklch, var(--color-background-primary) 85%, var(--color-foreground-primary));
}

/* ── Flat: border only, transparent bg ─────────────────────────────────── */

.elevationFlat {
  box-shadow: inset 0 0 0 1px var(--_border);
  color: var(--color-foreground-secondary);
}

/* ── None: ghost — transparent, no border, no shadow ───────────────────── */

.elevationNone {
  color: var(--color-foreground-secondary);
}

/* ── Floating: bg-primary + FAB-strength shadow ─────────────────────────── */

.elevationFloating {
  background-color: var(--color-background-primary);
  box-shadow: var(--effect-elevation-elevated-floating);
  color: var(--color-foreground-secondary);
  --_hover-bg: color-mix(in oklch, var(--color-background-primary) 90%, var(--color-foreground-primary));
  --_pressed-bg: color-mix(in oklch, var(--color-background-primary) 85%, var(--color-foreground-primary));
}

/* ── Fg on bold / strong surface ────────────────────────────────────────── */

.onBold.elevationNone, .onBold.elevationFlat,
.onStrong.elevationNone, .onStrong.elevationFlat {
  color: var(--color-foreground-on-bold-background-secondary);
}

/* ── Fg on always-dark surface ─────────────────────────────────────────── */

.onAlwaysDark.elevationNone, .onAlwaysDark.elevationFlat {
  color: var(--color-always-dark-foreground-secondary);
}

/* ==========================================================================
   Pressed state — shared across all elevation levels
   ========================================================================== */

.pressed {
  background-color: var(--color-background-faint-brand);
  color: var(--color-foreground-bold-brand);
}

/* ==========================================================================
   Layout
   ========================================================================== */

.iconOnly    { padding: 0; width: var(--dimension-size-400); min-width: var(--dimension-size-400); }
.labelOnly   { padding: 0 var(--dimension-space-100); }
.iconAndLabel { padding: 0 var(--dimension-space-100) 0 var(--dimension-space-075); gap: var(--dimension-space-025); }

/* ==========================================================================
   Sizes
   ========================================================================== */

.sizeSM { height: var(--dimension-size-300); }
.sizeSM.iconOnly { width: var(--dimension-size-300); min-width: var(--dimension-size-300); }
.sizeSM.labelOnly   { padding: 0 var(--dimension-space-075); }
.sizeSM.iconAndLabel { padding: 0 var(--dimension-space-075) 0 var(--dimension-space-050); gap: 0; }

.sizeXS { height: var(--dimension-size-200); }
.sizeXS.iconOnly { width: var(--dimension-size-200); min-width: var(--dimension-size-200); }
.sizeXS.labelOnly, .sizeXS.iconAndLabel { padding: 0 var(--dimension-space-025); gap: 0; }

/* ==========================================================================
   Rounded (pill shape)
   ========================================================================== */

.rounded { border-radius: var(--dimension-radius-half); }
.rounded.labelOnly   { padding-left: calc(var(--dimension-space-100) + var(--dimension-space-050)); padding-right: calc(var(--dimension-space-100) + var(--dimension-space-050)); }
.rounded.iconAndLabel { padding-left: calc(var(--dimension-space-075) + var(--dimension-space-050)); padding-right: calc(var(--dimension-space-100) + var(--dimension-space-050)); }
.rounded.sizeSM.labelOnly   { padding-left: calc(var(--dimension-space-075) + var(--dimension-space-050)); padding-right: calc(var(--dimension-space-075) + var(--dimension-space-050)); }
.rounded.sizeSM.iconAndLabel { padding-left: calc(var(--dimension-space-050) + var(--dimension-space-050)); padding-right: calc(var(--dimension-space-075) + var(--dimension-space-050)); }
.rounded.iconOnly { width: var(--dimension-size-400); min-width: var(--dimension-size-400); padding: 0; }
.rounded.sizeSM.iconOnly { width: var(--dimension-size-300); min-width: var(--dimension-size-300); }
.rounded.sizeXS.iconOnly { width: var(--dimension-size-200); min-width: var(--dimension-size-200); }

/* ==========================================================================
   Disabled
   ========================================================================== */

.inactive { opacity: 0.5; cursor: not-allowed; pointer-events: none; }

/* ==========================================================================
   Inner slots
   ========================================================================== */

.toggle-btn__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  line-height: 0;
}

.toggle-btn__label {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

import { Component, Prop, Event, EventEmitter, h, Host } from '@stencil/core';
import type { IconSize } from '../Icon/Icon';
import { resolveCssLengthPx, TOKEN_DEFAULTS } from '../../utils';

export type ToggleButtonElevation  = 'none' | 'flat' | 'elevated' | 'floating';
export type ToggleButtonSize       = 'md' | 'sm' | 'xs';
export type ToggleButtonBackground = 'faint' | 'medium' | 'bold' | 'strong' | 'always-dark';

const ICON_SIZE: Record<ToggleButtonSize, IconSize> = { md: 'md', sm: 'sm', xs: 'xs' };

const ICON_TOKEN: Record<ToggleButtonSize, string> = {
  md: TOKEN_DEFAULTS.iconographyMd,
  sm: TOKEN_DEFAULTS.iconographySm,
  xs: TOKEN_DEFAULTS.iconographyXs,
};

const TEXT_CLASS: Record<ToggleButtonSize, string> = {
  md: 'text-body-medium-emphasis',
  sm: 'text-body-small-emphasis',
  xs: 'text-caption-emphasis',
};

@Component({
  tag: 'ds-toggle-button',
  styleUrl: 'ToggleButton.css',
  scoped: true,
})
export class ToggleButton {
  /**
   * Chrome level.
   *   none     — ghost (transparent, no border, no shadow)
   *   flat     — border only, transparent bg
   *   elevated — bg-primary + shadow  [default]
   *   floating — bg-primary + FAB-strength shadow
   */
  @Prop() elevation: ToggleButtonElevation = 'elevated';

  /** Label text. */
  @Prop() label: string | undefined;

  /**
   * Icon name for <ds-icon>. Set via JS property.
   * @example el.icon = 'GridView';
   */
  @Prop() icon: string | undefined;

  /** Size: md (32px), sm (24px), xs (16px). */
  @Prop() size: ToggleButtonSize = 'md';

  /** Pill shape. */
  @Prop() rounded: boolean = false;

  /** Parent surface context — adjusts hover tokens for colored backgrounds. */
  @Prop() background: ToggleButtonBackground | undefined;

  /** Controlled pressed state. */
  @Prop({ mutable: true }) pressed: boolean = false;

  /** Disables interaction. */
  @Prop() inactive: boolean = false;

  @Prop({ attribute: 'aria-label' }) ariaLabel: string | undefined;

  /** Emits the new pressed value (!pressed) on click. */
  @Event() dsChange!: EventEmitter<boolean>;

  private handleClick = () => {
    if (this.inactive) return;
    this.dsChange.emit(!this.pressed);
  };

  render() {
    const size = this.size;
    const iconSize = ICON_SIZE[size];
    const iconPx = resolveCssLengthPx(ICON_TOKEN[size], ICON_TOKEN[size]);
    const textClass = TEXT_CLASS[size];
    const hasIcon = !!this.icon;
    const hasLabel = !!this.label;
    const isIconOnly = hasIcon && !hasLabel;
    const isLabelOnly = hasLabel && !hasIcon;
    const isIconAndLabel = hasIcon && hasLabel;
    const bg = this.background;
    const elevKey = this.elevation.charAt(0).toUpperCase() + this.elevation.slice(1);

    const cls: Record<string, boolean> = {
      'toggle-btn': true,
      [`elevation${elevKey}`]: true,
      sizeSM: size === 'sm',
      sizeXS: size === 'xs',
      rounded: this.rounded,
      inactive: this.inactive,
      pressed: this.pressed,
      iconOnly: isIconOnly,
      labelOnly: isLabelOnly,
      iconAndLabel: isIconAndLabel,
      onMedium: bg === 'medium',
      onBold: bg === 'bold',
      onStrong: bg === 'strong',
      onAlwaysDark: bg === 'always-dark',
    };

    return (
      <Host>
        <button
          type="button"
          class={cls}
          disabled={this.inactive}
          aria-label={this.ariaLabel ?? this.label ?? 'toggle'}
          aria-pressed={this.pressed}
          onClick={this.handleClick}
        >
          {hasIcon && (
            <span class="toggle-btn__icon" style={{ fontSize: `${iconPx}px` }}>
              <ds-icon name={this.icon} size={iconSize} />
            </span>
          )}
          {hasLabel && (
            <span class={`toggle-btn__label ${textClass}`}>{this.label}</span>
          )}
        </button>
      </Host>
    );
  }
}
